resources.preRequestScript:
const runId = Date.now().toString();
const now = Date.now();
const start = new Date(now + 2 * 60 * 60 * 1000);
const end = new Date(start.getTime() + 60 * 60 * 1000);
const rescheduledStart = new Date(now + 4 * 60 * 60 * 1000);
const rescheduledEnd = new Date(rescheduledStart.getTime() + 60 * 60 * 1000);
const sessionStart = new Date(now + 5 * 60 * 1000);
const sessionEnd = new Date(sessionStart.getTime() + 60 * 60 * 1000);
const cancelStart = new Date(now + 24 * 60 * 60 * 1000);
const cancelEnd = new Date(cancelStart.getTime() + 60 * 60 * 1000);
const noShowStart = new Date(now + 60 * 1000);
const noShowEnd = new Date(noShowStart.getTime() + 45 * 60 * 1000);
insomnia.baseEnvironment.set('run_id', runId);
insomnia.baseEnvironment.set('start_at', start.toISOString());
insomnia.baseEnvironment.set('end_at', end.toISOString());
insomnia.baseEnvironment.set('rescheduled_start_at', rescheduledStart.toISOString());
insomnia.baseEnvironment.set('rescheduled_end_at', rescheduledEnd.toISOString());
insomnia.baseEnvironment.set('session_start_at', sessionStart.toISOString());
insomnia.baseEnvironment.set('session_end_at', sessionEnd.toISOString());
insomnia.baseEnvironment.set('cancel_start_at', cancelStart.toISOString());
insomnia.baseEnvironment.set('cancel_end_at', cancelEnd.toISOString());
insomnia.baseEnvironment.set('no_show_start_at', noShowStart.toISOString());
insomnia.baseEnvironment.set('no_show_end_at', noShowEnd.toISOString());
insomnia.baseEnvironment.set('window_from', new Date(now - 60 * 1000).toISOString());
insomnia.baseEnvironment.set('window_to', new Date(now + 48 * 60 * 60 * 1000).toISOString());

resources.afterResponseScript:
const body = insomnia.response.json();
insomnia.baseEnvironment.set('admin_token', body.access_token);
insomnia.test('administrator login returns 200', () => insomnia.expect(insomnia.response.code).to.eql(200));

const body = insomnia.response.json();
insomnia.baseEnvironment.set('facility_id', body.id);
insomnia.test('facility creation returns 201', () => insomnia.expect(insomnia.response.code).to.eql(201));

const body = insomnia.response.json();
insomnia.baseEnvironment.set('station_id', body.id);
insomnia.baseEnvironment.set('connector_id', body.connectors[0].id);
insomnia.test('station creation returns 201', () => insomnia.expect(insomnia.response.code).to.eql(201));

const body = insomnia.response.json();
insomnia.baseEnvironment.set('driver_token', body.access_token);
insomnia.test('driver login returns 200', () => insomnia.expect(insomnia.response.code).to.eql(200));

const body = insomnia.response.json();
insomnia.baseEnvironment.set('vehicle_id', body.id);
insomnia.test('vehicle creation returns 201', () => insomnia.expect(insomnia.response.code).to.eql(201));

const body = insomnia.response.json();
insomnia.baseEnvironment.set('reservation_id', body.reservation.id);
insomnia.test('reservation creation returns 201', () => insomnia.expect(insomnia.response.code).to.eql(201));

const body = insomnia.response.json();
insomnia.baseEnvironment.set('created_event_id', body[0].id);
insomnia.test('administrator filter returns one event', () => { insomnia.expect(insomnia.response.code).to.eql(200); insomnia.expect(body).to.have.length(1); });
insomnia.test('ReservationCreated V1 envelope is exact', () => { const event = body[0]; insomnia.expect(event.event_type).to.eql('reservation.created'); insomnia.expect(event.event_version).to.eql(1); insomnia.expect(event.aggregate_id).to.eql(insomnia.baseEnvironment.get('reservation_id')); insomnia.expect(event.aggregate_type).to.eql('Reservation'); insomnia.expect(event.producer_module).to.eql('charging'); insomnia.expect(event.payload).to.have.all.keys('owner_id', 'vehicle_id', 'connector_id', 'start_at', 'end_at'); });

const body = insomnia.response.json();
insomnia.baseEnvironment.set('reservation_id', body.reservation.id);
insomnia.test('near-term session reservation returns 201', () => insomnia.expect(insomnia.response.code).to.eql(201));

const body = insomnia.response.json();
insomnia.baseEnvironment.set('session_id', body.id);
insomnia.baseEnvironment.set('recorded_at', new Date(new Date(body.started_at).getTime() + 1000).toISOString());
insomnia.test('activation returns 201', () => insomnia.expect(insomnia.response.code).to.eql(201));

const body = insomnia.response.json();
insomnia.baseEnvironment.set('telemetry_id', body.id);
insomnia.test('first telemetry ingestion returns 201', () => insomnia.expect(insomnia.response.code).to.eql(201));

const body = insomnia.response.json();
insomnia.test('identical retry returns 200', () => insomnia.expect(insomnia.response.code).to.eql(200));
insomnia.test('retry returns canonical telemetry ID', () => insomnia.expect(body.id).to.eql(insomnia.baseEnvironment.get('telemetry_id')));

const body = insomnia.response.json();
const types = body.map(item => item.event_type);
insomnia.test('started and completed V1 events exist', () => { insomnia.expect(body).to.have.length(2); insomnia.expect(types).to.include('charging-session.started'); insomnia.expect(types).to.include('charging-session.completed'); insomnia.expect(body.every(item => item.event_version === 1)).to.eql(true); });

const body = insomnia.response.json();
insomnia.baseEnvironment.set('cancel_reservation_id', body.reservation.id);
insomnia.test('cancellation candidate returns 201', () => insomnia.expect(insomnia.response.code).to.eql(201));

const body = insomnia.response.json();
const list = body.paths['/domain-events'];
const detail = body.paths['/domain-events/{eventId}'];
insomnia.test('OpenAPI documents both reads and no writes', () => { insomnia.expect(list.get).to.be.an('object'); insomnia.expect(detail.get).to.be.an('object'); insomnia.expect(Object.keys(list)).to.eql(['get']); insomnia.expect(Object.keys(detail)).to.eql(['get']); });
const names = list.get.parameters.map(item => item.name);
insomnia.test('OpenAPI documents all list filters and pagination', () => ['event_type','aggregate_type','aggregate_id','producer_module','occurred_from','occurred_to','consumer','delivery_status','offset','limit'].forEach(name => insomnia.expect(names).to.include(name)));

const body = insomnia.response.json();
insomnia.baseEnvironment.set('no_show_reservation_id', body.reservation.id);
insomnia.test('near-term reservation returns 201', () => insomnia.expect(insomnia.response.code).to.eql(201));
